  #[allow(dead_code)]
  fn u_r_l_search_params_construct(
    vm: &mut Vm,
    scope: &mut Scope<'_>,
    host: &mut dyn VmHost,
    hooks: &mut dyn VmHostHooks,
    callee: GcObject,
    args: &[Value],
    new_target: Value,
  ) -> Result<Value, VmError> {
    let mut bindings_host = {
      let host = host_from_hooks(hooks)?;
      NonNull::from(host)
    };
    let mut cx =
      VmJsWebIdlCx::from_native_call(vm, scope, host, hooks, WebIdlLimits::default(), &NO_HOOKS);
    let slots = cx.scope.heap().get_function_native_slots(callee)?;
    let proto_slot = slots.get(0).copied().unwrap_or(Value::Undefined);
    let Value::Object(default_proto) = proto_slot else {
      return Err(VmError::InvariantViolation(
        "URLSearchParams constructor missing prototype slot",
      ));
    };
    // Derive the wrapper object's prototype from `new.target` (subclassing semantics).
    //
    // This follows the spirit of `GetPrototypeFromConstructor` / `OrdinaryCreateFromConstructor`:
    // - default to the interface prototype cached in native slots,
    // - if `new_target` is an object and `new_target.prototype` is an object, use that instead.
    cx.scope.push_root(Value::Object(default_proto))?;
    cx.scope.push_root(new_target)?;
    let mut wrapper_proto = default_proto;
    if let Value::Object(new_target_obj) = new_target {
      cx.scope.push_root(Value::Object(new_target_obj))?;
      let proto_key = cx.property_key_from_str("prototype")?;
      let candidate = cx.get(Value::Object(new_target_obj), proto_key)?;
      if let Value::Object(candidate_obj) = candidate {
        cx.scope.push_root(Value::Object(candidate_obj))?;
        wrapper_proto = candidate_obj;
      }
    }
    let obj = cx.scope.alloc_object_with_prototype(Some(wrapper_proto))?;
    cx.scope.push_root(Value::Object(obj))?;

    static ARG_SCHEMAS: OnceLock<Vec<Vec<ArgumentSchema>>> = OnceLock::new();
    let arg_schemas = ARG_SCHEMAS.get_or_init(|| {
      vec![vec![ArgumentSchema {
        name: "init",
        ty: IdlType::Union(vec![
          IdlType::Sequence(Box::new(IdlType::Sequence(Box::new(IdlType::String(
            StringType::UsvString,
          ))))),
          IdlType::Record(
            Box::new(IdlType::String(StringType::UsvString)),
            Box::new(IdlType::String(StringType::UsvString)),
          ),
          IdlType::String(StringType::UsvString),
        ]),
        optional: true,
        variadic: false,
        default: Some(DefaultValue::String("".to_string())),
      }]]
    });
    let overload_index: usize = { 0 };
    let params = &arg_schemas[overload_index];
    let ctx = type_context();
    let converted_args = convert_arguments(&mut cx, args, params, ctx)?;
    let mut converted_js_args: Vec<Value> = Vec::with_capacity(converted_args.len());
    for value in converted_args {
      converted_js_args.push(converted_value_to_js(&mut cx, value)?);
    }
    let bindings_host = unsafe { bindings_host.as_mut() };
    let _ = bindings_host.call_operation(
      cx.vm,
      &mut cx.scope,
      Some(Value::Object(obj)),
      "URLSearchParams",
      "constructor",
      overload_index,
      &converted_js_args,
    )?;
    Ok(Value::Object(obj))
  }

  pub fn install_event_target_bindings_vm_js(
    vm: &mut Vm,
    heap: &mut Heap,
    realm: &Realm,
  ) -> Result<(), VmError> {
    let mut rt = BindingsRuntime::new(vm, heap);
    let global = realm.global_object();
    rt.scope.push_root(Value::Object(global))?;

    let key = rt.property_key("EventTarget")?;
    if rt
      .scope
      .heap()
      .object_get_own_property(global, &key)?
      .is_some()
    {
      return Ok(());
    }

    let global_var_attrs = DataPropertyAttributes::new(true, false, true);
    let ctor_link_attrs = DataPropertyAttributes::new(false, false, false);

    let proto_event_target = rt.alloc_object()?;
    let func =
      rt.alloc_native_function(event_target_add_event_listener, None, "addEventListener", 2)?;
    rt.define_data_property_str(
      proto_event_target,
      "addEventListener",
      Value::Object(func),
      DataPropertyAttributes::METHOD,
    )?;
    let func = rt.alloc_native_function(event_target_dispatch_event, None, "dispatchEvent", 1)?;
    rt.define_data_property_str(
      proto_event_target,
      "dispatchEvent",
      Value::Object(func),
      DataPropertyAttributes::METHOD,
    )?;
    let func = rt.alloc_native_function(
      event_target_remove_event_listener,
      None,
      "removeEventListener",
      2,
    )?;
    rt.define_data_property_str(
      proto_event_target,
      "removeEventListener",
      Value::Object(func),
      DataPropertyAttributes::METHOD,
    )?;
    let slots = [Value::Object(proto_event_target)];
    let ctor_event_target = rt.alloc_native_function_with_slots(
      event_target_call_without_new,
      Some(event_target_construct),
      "EventTarget",
      0,
      &slots,
    )?;
    rt.define_data_property_str(
      global,
      "EventTarget",
      Value::Object(ctor_event_target),
      global_var_attrs,
    )?;
    rt.define_data_property_str(
      ctor_event_target,
      "prototype",
      Value::Object(proto_event_target),
      ctor_link_attrs,
    )?;
    rt.define_data_property_str(
      proto_event_target,
      "constructor",
      Value::Object(ctor_event_target),
      ctor_link_attrs,
    )?;
    Ok(())
  }

  pub fn install_url_bindings_vm_js(
    vm: &mut Vm,
    heap: &mut Heap,
    realm: &Realm,
  ) -> Result<(), VmError> {
    let mut rt = BindingsRuntime::new(vm, heap);
    let global = realm.global_object();
    rt.scope.push_root(Value::Object(global))?;

    let key = rt.property_key("URL")?;
    if rt
      .scope
      .heap()
      .object_get_own_property(global, &key)?
      .is_some()
    {
      return Ok(());
    }

    let global_var_attrs = DataPropertyAttributes::new(true, false, true);
    let ctor_link_attrs = DataPropertyAttributes::new(false, false, false);

    let proto_u_r_l = rt.alloc_object()?;
    let func = rt.alloc_native_function(u_r_l_to_j_s_o_n, None, "toJSON", 0)?;
    rt.define_data_property_str(
      proto_u_r_l,
      "toJSON",
      Value::Object(func),
      DataPropertyAttributes::METHOD,
    )?;
    let get = rt.alloc_native_function(u_r_l_get_attribute_href, None, "get href", 0)?;
    let set =
      Value::Object(rt.alloc_native_function(u_r_l_set_attribute_href, None, "set href", 1)?);
    rt.define_accessor_property_str(
      proto_u_r_l,
      "href",
      Value::Object(get),
      set,
      AccessorPropertyAttributes::ATTRIBUTE,
    )?;
    let get = rt.alloc_native_function(u_r_l_get_attribute_origin, None, "get origin", 0)?;
    let set = Value::Undefined;
    rt.define_accessor_property_str(
      proto_u_r_l,
      "origin",
      Value::Object(get),
      set,
      AccessorPropertyAttributes::ATTRIBUTE,
    )?;
    let slots = [Value::Object(proto_u_r_l)];
    let ctor_u_r_l = rt.alloc_native_function_with_slots(
      u_r_l_call_without_new,
      Some(u_r_l_construct),
      "URL",
      1,
      &slots,
    )?;
    rt.define_data_property_str(global, "URL", Value::Object(ctor_u_r_l), global_var_attrs)?;
    rt.define_data_property_str(
      ctor_u_r_l,
      "prototype",
      Value::Object(proto_u_r_l),
      ctor_link_attrs,
    )?;
    rt.define_data_property_str(
      proto_u_r_l,
      "constructor",
      Value::Object(ctor_u_r_l),
      ctor_link_attrs,
    )?;
    let func = rt.alloc_native_function(u_r_l_can_parse, None, "canParse", 1)?;
    rt.define_data_property_str(
      ctor_u_r_l,
      "canParse",
      Value::Object(func),
      DataPropertyAttributes::METHOD,
    )?;
    let func = rt.alloc_native_function(u_r_l_parse, None, "parse", 1)?;
    rt.define_data_property_str(
      ctor_u_r_l,
      "parse",
      Value::Object(func),
      DataPropertyAttributes::METHOD,
    )?;
    Ok(())
  }

