  pub fn install_worker_bindings_vm_js(
    vm: &mut Vm,
    heap: &mut Heap,
    realm: &Realm,
  ) -> Result<(), VmError> {
    install_event_target_bindings_vm_js(vm, heap, realm)?;
    install_url_bindings_vm_js(vm, heap, realm)?;
    install_url_search_params_bindings_vm_js(vm, heap, realm)?;
    Ok(())
  }
